#![allow(unused)]
fn main() {
    let mut x = vec![1];
    let mut y = vec![2];

    swap(&mut x, &mut y);
}

fn swap(a: &mut Vec<i32>, b: &mut Vec<i32>) {
    let temp = a.clone();
    *a = b.clone();
    *b = temp;
}

